// Access headers/body
const secret = $env.SHARED_SECRET || '';
const hdr = $json.headers || {};
const got = (hdr['x-shared-secret'] || hdr['X-Shared-Secret'] || hdr['x-shared-secret'.toLowerCase()]);
if (secret && got !== secret) {
  throw new Error('Unauthorized: shared secret mismatch');
}

// Pass through body (Google Forms Apps Script posts JSON fields)
const body = $json.body || $json;

// coerce numeric quantities if provided
function num(x){
  const v = (x==null? '' : String(x).trim());
  if (!v) return 0; const n = parseInt(v,10); return isNaN(n)?0:n;
}

return [{ json: {
  ...body,
  sub_qty: num(body.sub_qty),
  smallbite_qty: num(body.smallbite_qty),
  fries_qty: num(body.fries_qty),
  drink_qty: num(body.drink_qty)
}}];

const f = $json;
const TIMEZONE = $env.TIMEZONE || 'America/Chicago';
const OPEN = ($env.HOURS_OPEN || '09:00').split(':').map(Number);
const CLOSE = ($env.HOURS_CLOSE || '23:00').split(':').map(Number);
const TAX_RATE = parseFloat($env.TAX_RATE || '0.10825');

function nowInTZ(tz){ const d=new Date(); return new Date(d.toLocaleString('en-US',{timeZone:tz})); }
function minutes(d){ return d.getHours()*60 + d.getMinutes(); }

const ct = nowInTZ(TIMEZONE);
const in_hours = (minutes(ct) >= (OPEN[0]*60+OPEN[1]) && minutes(ct) < (CLOSE[0]*60+CLOSE[1]));

// Price map (cents)
const PRICE = {
  "Cowboy Chik’n": 1300,
  "Philly Chsteek": 1300,
  "Chik’n Club Sub": 1300,
  "Chik’n Fried Chik’n": 1300,
  "Chik’n Poppers ($10)": 1000,
  "Korean Popper ($12)": 1200,
  "Dumpling Taco ($10)": 1000,
  "Rocktown Bourbon Bites ($12)": 1200,
  "Chik’n Sliders ($13)": 1300,
  "Loaded Bacon Fries ($13)": 1300,
  "Philly Fries ($13)": 1300,
  "Chik’n or Stek Fries ($13)": 1300,
  "Garlic Parm Fries ($14)": 1400,
  "Just Fries ($5)": 500,
  "Water ($2)": 200,
  "Sea Moss Lemonade ($6)": 600
};

let items = [];
function push(name, qty){
  if (!name) return;
  const key = Object.keys(PRICE).find(k => k.startsWith(name)) || name;
  const amount = PRICE[key] || 0;
  const q = qty>0? qty : 0;
  if (q>0) items.push({ name: key, quantity: q, base_price_money: { amount, currency: 'USD' } });
}

push(f.sub_choice, f.sub_qty);
push(f.smallbite_choice, f.smallbite_qty);
push(f.fries_choice, f.fries_qty);

if (f.drink_type){
  const drinkName = f.drink_type; // already includes price in map keys
  const q = f.drink_qty>0? f.drink_qty:0;
  if (q>0) items.push({ name: drinkName + (f.lemonade_flavor? ` – ${f.lemonade_flavor}`:''), quantity: q, base_price_money: { amount: PRICE[drinkName]||0, currency:'USD' } });
}

const subtotal = items.reduce((s,i)=> s + i.base_price_money.amount * i.quantity, 0);
const tax = Math.round(subtotal * TAX_RATE);
const total = subtotal + tax;

return [{ json: {
  ...f,
  ct_iso: ct.toISOString(),
  in_hours,
  items,
  subtotal,
  tax,
  total,
  idempotency_key: f.order_id || $uuid()
}}];
